export const bySlug = Object.fromEntries(TOOLS.map(t => [t.slug, t]));
export const byId = Object.fromEntries(TOOLS.map(t => [t.id, t]));
export const toolsByCat = (c) => TOOLS.filter(t => t.cat === c);
export function seoTitle(t){ const base = t.name + ' \u2013 Free Online Tool'; return base.length <= 60 ? base : (t.name + ' \u2013 UtilityHub'); }
export function seoDescription(t){ const d = t.desc.replace(/\s+$/, '').replace(/[.]$/, ''); const s = d + ' \u2014 free, fast and 100% private, right in your browser. No signup, no uploads.'; return s.length <= 160 ? s : t.desc; }
